from typing import List

class Solution:
    def minOperations(self, nums1: List[int], nums2: List[int]) -> int:
        n = len(nums1)
        max1 = max(nums1)
        max2 = max(nums2)

        # Check if the last elements can be max in their arrays
        if nums1[-1] != max1 and nums2[-1] != max2:
            # Check if swapping the last elements can fix it
            if nums1[-1] == max2 and nums2[-1] == max1:
                return 1
            else:
                return -1

        # If one of the last elements is already max
        if nums1[-1] == max1 and nums2[-1] == max2:
            return 0

        # If only one of the last elements is max
        if nums1[-1] == max1:
            # Need to swap to get max2 in nums2[-1]
            for i in range(n - 1):
                if nums2[i] == max2:
                    return 1
            return -1
        elif nums2[-1] == max2:
            # Need to swap to get max1 in nums1[-1]
            for i in range(n - 1):
                if nums1[i] == max1:
                    return 1
            return -1
        else:
            return -1
